from machine import Pin, ADC
import network
import time
from umqtt.simple import MQTTClient

# Wi-Fi configuration
ssid = 'your_ssid'
password = 'your_password'

# MQTT configuration
client_id = 'esp32_sensor'
broker_ip = 'broker_ip_address'
topic = 'sensors/temp'

# Connect to Wi-Fi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(ssid, password)
    while not wlan.isconnected():
        time.sleep(1)
    print('Connected to Wi-Fi')

# Read temperature from sensor
def read_temperature():
    adc = ADC(Pin(34))
    adc.atten(ADC.ATTN_11DB)
    adc.width(ADC.WIDTH_12BIT)
    raw_value = adc.read()
    temperature = (raw_value / 4095.0) * 100  # Example conversion
    return temperature

# Secure MQTT connection
def connect_mqtt():
    client = MQTTClient(client_id, broker_ip, ssl=True)
    client.connect()
    return client

# Main function
def main():
    connect_wifi()
    client = connect_mqtt()
    try:
        while True:
            temperature = read_temperature()
            client.publish(topic, str(temperature))
            print('Published:', temperature)
            time.sleep(10)
    finally:
        client.disconnect()

if __name__ == '__main__':
    main()